#include <stdio.h>
#include <stdlib.h>

#define MAX_FRAMES 10
#define MAX_PAGES 100

int find_lru(int frames[], int time[], int n) {
    int min = time[0], lru_index = 0;
    for (int i = 1; i < n; i++) {
        if (time[i] < min) {
            min = time[i];
            lru_index = i;
        }
    }
    return lru_index;
}

int lru_page_replacement(int pages[], int n, int frames, int frame_count) {
    int frame_array[MAX_FRAMES];
    int time[MAX_FRAMES];
    int page_faults = 0, counter = 0;

    // Initialize frames to -1 (empty)
    for (int i = 0; i < frame_count; i++) {
        frame_array[i] = -1;
        time[i] = 0;
    }

    for (int i = 0; i < n; i++) {
        int page = pages[i];
        int found = 0;

        // Check if page is already in memory
        for (int j = 0; j < frame_count; j++) {
            if (frame_array[j] == page) {
                found = 1;
                time[j] = counter++;  // Update recent use time
                break;
            }
        }

        if (!found) {
            page_faults++;
            // Find empty frame or LRU frame
            int replace_index = -1;
            for (int j = 0; j < frame_count; j++) {
                if (frame_array[j] == -1) {
                    replace_index = j;
                    break;
                }
            }

            if (replace_index == -1) {
                replace_index = find_lru(frame_array, time, frame_count);
            }

            frame_array[replace_index] = page;
            time[replace_index] = counter++;
        }
    }
    return page_faults;
}

int main() {
    int pages[] = {7, 0, 1, 2, 0, 3, 0, 4, 2, 3, 0, 3, 2};
    int n = sizeof(pages) / sizeof(pages[0]);
    int frame_count = 3;

    int faults = lru_page_replacement(pages, n, 0, frame_count);
    printf("LRU Page Faults: %d\n", faults);
    return 0;
}

// Virtual Address Structure
// [Page Number | Offset]
// Bits: [p bits | d bits]
// where p = number of bits for page number
//       d = number of bits for offset (page size = 2^d)

ALGORITHM Translate_Virtual_To_Physical(virtual_address, page_table)
BEGIN
    // Extract page number and offset from virtual address
    page_number = virtual_address / PAGE_SIZE
    offset = virtual_address % PAGE_SIZE

    PRINT "Virtual Address: " + virtual_address
    PRINT "Page Number: " + page_number
    PRINT "Offset: " + offset

    // Look up page table entry
    pte = page_table[page_number]

    // Check if page is in memory (valid bit)
    IF pte.valid_bit == 0 THEN
        // Page fault - page not in memory
        PRINT "PAGE FAULT!"
        Handle_Page_Fault(page_number)
        // After handling, retry the lookup
        pte = page_table[page_number]
    END IF

    // Get physical frame number
    frame_number = pte.frame_number

    // Calculate physical address
    physical_address = (frame_number * PAGE_SIZE) + offset

    PRINT "Physical Address: " + physical_address
    RETURN physical_address
END

// Page Table Entry Structure
// [Frame Number | Valid Bit | Dirty Bit | Protection Bits]
DATA STRUCTURE PageTableEntry
BEGIN
    frame_number : INTEGER    // Physical frame where page resides
    valid_bit : BOOLEAN      // 1 = page in memory, 0 = not in memory
    dirty_bit : BOOLEAN      // 1 = page modified, 0 = not modified
    protection : INTEGER    // Read/Write/Execute permissions
    reference_bit : BOOLEAN  // For page replacement algorithms
END
